using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain static queue to ensure isolation between tests
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_CreatesCorrectNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsTrue(notification.Message.Contains("John Doe"));
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.IsTrue(notification.Message.Contains("ID: 42"),
            $"Expected message to contain 'ID: 42' but was '{notification.Message}'");
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = DateTime.Now;
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesInOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", EntityOperation.DELETE);

        // Act
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("A", first!.EntityType);
        Assert.AreEqual("B", second!.EntityType);
        Assert.AreEqual("C", third!.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_ExceedsQueueCap_EnforcesMaxLength()
    {
        // Arrange & Act - enqueue more than the 500 cap
        for (int i = 0; i < 510; i++)
        {
            _sut.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        // Assert - drain and count
        int count = 0;
        while (_sut.ReceiveNotification() != null) { count++; }

        Assert.IsTrue(count <= 500, $"Expected ≤500 but got {count}");
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "has been created", DisplayName = "CREATE generates created message")]
    [DataRow(EntityOperation.UPDATE, "has been updated", DisplayName = "UPDATE generates updated message")]
    [DataRow(EntityOperation.DELETE, "has been deleted", DisplayName = "DELETE generates deleted message")]
    public void GenerateMessage_ReturnsCorrectMessageForOperation(EntityOperation operation, string expectedFragment)
    {
        // Act
        _sut.SendNotification("Student", "1", "Test Student", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains(expectedFragment),
            $"Expected message to contain '{expectedFragment}' but was '{notification.Message}'");
    }

    [TestMethod]
    public void GenerateMessage_WithDisplayName_IncludesEntityTypeAndName()
    {
        // Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("Department"));
        Assert.IsTrue(notification.Message.Contains("Engineering"));
    }

    [TestMethod]
    public void GenerateMessage_WithoutDisplayName_IncludesEntityTypeAndId()
    {
        // Act
        _sut.SendNotification("Department", "5", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("Department"));
        Assert.IsTrue(notification.Message.Contains("ID: 5"));
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert - should not throw
        service.Dispose();
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - no-op implementation should not throw
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void SendNotification_OverloadWithoutDisplayName_SetsFieldsCorrectly()
    {
        // Act
        _sut.SendNotification("Instructor", "7", EntityOperation.UPDATE, "teacher1");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.AreEqual("7", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("teacher1", notification.CreatedBy);
    }
}

