using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_HasCorrectProperties()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_MiddlePage_HasBothNavigation()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_LastPage_HasPreviousOnly()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SinglePage_NoPagination()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(1, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(0, result.Count);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void TotalPages_CeilingDivision_RoundsUp()
    {
        // Arrange - 11 items / 10 per page = 2 pages (ceiling)
        var source = Enumerable.Range(1, 11).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(2, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_ExactDivision_NoExtraPage()
    {
        // Arrange - 20 items / 10 per page = exactly 2 pages
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(2, result.TotalPages);
    }

    [TestMethod]
    [DataRow(1, 10, 1, DisplayName = "First page starts at item 1")]
    [DataRow(2, 10, 11, DisplayName = "Second page starts at item 11")]
    [DataRow(3, 5, 11, DisplayName = "Third page of size 5 starts at item 11")]
    public void Create_CorrectItems_ForPageIndex(int pageIndex, int pageSize, int expectedFirstItem)
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expectedFirstItem, result[0]);
    }

    [TestMethod]
    public void Create_PageSizeOne_CreatesCorrectPages()
    {
        // Arrange
        var source = Enumerable.Range(1, 3).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 1);

        // Assert
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(2, result[0]);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Constructor_SetsPropertiesCorrectly()
    {
        // Arrange & Act
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
        Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        Assert.AreEqual(3, list.Count);
        CollectionAssert.AreEqual(items, list.ToList());
    }
}

