using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private string _dbName = null!;

    [TestInitialize]
    public void Setup()
    {
        _dbName = Guid.NewGuid().ToString();
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    private SchoolContext CreateContext() => TestHelpers.CreateContext(_dbName);

    private StudentsController CreateController(SchoolContext context)
    {
        var controller = new StudentsController(context);
        // Set up TempData for actions that use it (e.g., DeleteConfirmed error path)
        controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
        return controller;
    }

    private void SeedStudents()
    {
        using var context = CreateContext();
        context.Students.AddRange(
            new Student { LastName = "Apple", FirstMidName = "Alice", EnrollmentDate = new DateTime(2020, 1, 1) },
            new Student { LastName = "Cherry", FirstMidName = "Charlie", EnrollmentDate = new DateTime(2021, 6, 15) },
            new Student { LastName = "Zebra", FirstMidName = "Zach", EnrollmentDate = new DateTime(2022, 9, 1) }
        );
        context.SaveChanges();
    }

    // ===================== Index Tests =====================

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Apple", model[0].LastName);
        Assert.AreEqual("Cherry", model[1].LastName);
        Assert.AreEqual("Zebra", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual("Zebra", model![0].LastName);
        Assert.AreEqual("Cherry", model[1].LastName);
        Assert.AreEqual("Apple", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual("Apple", model![0].LastName);   // 2020-01-01
        Assert.AreEqual("Cherry", model[1].LastName);    // 2021-06-15
        Assert.AreEqual("Zebra", model[2].LastName);     // 2022-09-01
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual("Zebra", model![0].LastName);    // 2022-09-01
        Assert.AreEqual("Cherry", model[1].LastName);    // 2021-06-15
        Assert.AreEqual("Apple", model[2].LastName);     // 2020-01-01
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersCorrectly()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, "Apple", null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Apple", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, "Charlie", null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Cherry", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_ResetsPageToOne()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act - pass page=5 with a searchString; page should reset to 1
        var result = controller.Index(null, null, "Apple", 5) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act - null searchString should use currentFilter
        var result = controller.Index(null, "Apple", null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Apple", model[0].LastName);
    }

    [TestMethod]
    public void Index_Pagination_ReturnsCorrectPage()
    {
        // Arrange - seed 15 students for pagination (page size is 10)
        using (var seedContext = CreateContext())
        {
            for (int i = 0; i < 15; i++)
            {
                seedContext.Students.Add(new Student
                {
                    LastName = $"Student{i:D2}",
                    FirstMidName = "Test",
                    EnrollmentDate = DateTime.Today
                });
            }
            seedContext.SaveChanges();
        }
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, null, 2) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(2, model!.PageIndex);
        Assert.AreEqual(5, model.Count); // 15 total, 10 per page, page 2 has 5
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        controller.Index(null, null, null, null);

        // Assert
        Assert.AreEqual("name_desc", controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithSortOrder_TogglesParameters()
    {
        // Arrange
        SeedStudents();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act - when sortOrder is "Date", DateSortParm should toggle to "date_desc"
        controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("", controller.ViewBag.NameSortParm);
        Assert.AreEqual("date_desc", controller.ViewBag.DateSortParm);
    }

    // ===================== Details Tests =====================

    [TestMethod]
    public void Details_ValidId_ReturnsStudentWithEnrollments()
    {
        // Arrange
        int studentId;
        using (var seedContext = CreateContext())
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today,
                Enrollments = new List<Enrollment>()
            };
            seedContext.Students.Add(student);
            seedContext.SaveChanges();
            studentId = student.ID;
        }
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Details(studentId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Test", model.LastName);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Details(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    // ===================== Create Tests =====================

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidModel_SavesAndRedirects()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = CreateController(context);
        var student = new Student
        {
            LastName = "New",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        // Act
        var result = controller.Create(student);

        // Assert
        Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        Assert.AreEqual(1, context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = CreateController(context);
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = controller.Create(student);

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
        Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
        Assert.AreEqual(0, context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_DateBefore1753_AddsModelError()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = CreateController(context);
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
