    }

    // ===================== Delete Tests =====================

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsStudent()
    {
        // Arrange
        int studentId;
        using (var seedContext = CreateContext())
        {
            var student = new Student
            {
                LastName = "Test",
