using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class CoursesControllerTests
{
    private string _dbName = null!;
    private Mock<IWebHostEnvironment> _envMock = null!;
    private Mock<ILogger<CoursesController>> _loggerMock = null!;
    private string _tempPath = null!;

    [TestInitialize]
    public void Setup()
    {
        _dbName = Guid.NewGuid().ToString();
        _envMock = new Mock<IWebHostEnvironment>();
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _tempPath = Path.Combine(Path.GetTempPath(), "CoursesTest_" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(_tempPath);
        _envMock.Setup(e => e.WebRootPath).Returns(_tempPath);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempPath);
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
        if (Directory.Exists(_tempPath))
        {
            try { Directory.Delete(_tempPath, true); } catch { /* best effort */ }
        }
    }

    private SchoolContext CreateContext() => TestHelpers.CreateContext(_dbName);

    private CoursesController CreateController(SchoolContext context)
    {
        return new CoursesController(context, _envMock.Object, _loggerMock.Object);
    }

    private void SeedDepartmentAndCourse()
    {
        using var context = CreateContext();
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000,
            StartDate = DateTime.Today
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();
    }

    private int GetDepartmentId()
    {
        using var context = CreateContext();
        return context.Departments.First().DepartmentID;
    }

    // ===================== Index Tests =====================

    [TestMethod]
    public void Index_ReturnsCoursesList()
    {
        // Arrange
        SeedDepartmentAndCourse();
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Intro to CS", model[0].Title);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

