        // Act
        var result = controller.Create(course, fileMock.Object);

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
        Assert.IsTrue(controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Create_Post_ValidImage_SavesFilePathAndRedirects()
    {
        // Arrange
        SeedDepartmentAndCourse();
        var deptId = GetDepartmentId();
        using var context = CreateContext();
        using var controller = CreateController(context);
        var course = new Course
        {
            CourseID = 2004,
            Title = "Image Course",
            Credits = 3,
            DepartmentID = deptId
        };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("photo.jpg");
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        // Act
        var result = controller.Create(course, fileMock.Object);

        // Assert
        Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        var savedCourse = context.Courses.Find(2004);
        Assert.IsNotNull(savedCourse);
        Assert.IsTrue(savedCourse.TeachingMaterialImagePath!.StartsWith("/Uploads/TeachingMaterials/"));
    }

    [TestMethod]
    [DataRow(".jpg", DisplayName = "JPG allowed")]
    [DataRow(".jpeg", DisplayName = "JPEG allowed")]
    [DataRow(".png", DisplayName = "PNG allowed")]
    [DataRow(".gif", DisplayName = "GIF allowed")]
    [DataRow(".bmp", DisplayName = "BMP allowed")]
    public void Create_Post_AllowedExtensions_AcceptsFile(string extension)
    {
        // Arrange
        SeedDepartmentAndCourse();
        var deptId = GetDepartmentId();
        using var context = CreateContext();
        using var controller = CreateController(context);
        var courseId = 3000 + Math.Abs(extension.GetHashCode() % 1000);
        var course = new Course
        {
            CourseID = courseId,
            Title = "Course",
            Credits = 3,
            DepartmentID = deptId
        };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns($"test{extension}");
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        // Act
        var result = controller.Create(course, fileMock.Object);

        // Assert
        Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
    }

