using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class InstructorsControllerTests
{
    private string _dbName = null!;

    [TestInitialize]
    public void Setup()
    {
        _dbName = Guid.NewGuid().ToString();
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    private SchoolContext CreateContext() => TestHelpers.CreateContext(_dbName);

    private (int instructorId, int courseId, int deptId) SeedInstructorWithCourseAndDepartment()
    {
        using var context = CreateContext();
        var dept = new Department
        {
            Name = "CS Dept",
            Budget = 100000,
            StartDate = DateTime.Today
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = dept.DepartmentID,
            Enrollments = new List<Enrollment>()
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var instructor = new Instructor
        {
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1001 }
            },
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        return (instructor.ID, 1001, dept.DepartmentID);
    }

    private int SeedInstructor()
    {
        using var context = CreateContext();
        var instructor = new Instructor
        {
            LastName = "Doe",
            FirstMidName = "Jane",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();
        return instructor.ID;
    }

    private void SeedCourses()
    {
        using var context = CreateContext();
        var dept = new Department
        {
            Name = "Test Dept",
            Budget = 50000,
            StartDate = DateTime.Today
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        context.Courses.AddRange(
            new Course { CourseID = 2001, Title = "Course A", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 2002, Title = "Course B", Credits = 3, DepartmentID = dept.DepartmentID }
        );
        context.SaveChanges();
    }

    // ===================== Index Tests =====================

    [TestMethod]
    public void Index_NoSelection_ReturnsInstructorList()
    {
        // Arrange
        SeedInstructor();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Instructors.Any());
        Assert.IsNull(model.Courses);
        Assert.IsNull(model.Enrollments);
    }

    [TestMethod]
    public void Index_InstructorSelected_ShowsCourses()
    {
        // Arrange
        var (instructorId, courseId, deptId) = SeedInstructorWithCourseAndDepartment();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Index(instructorId, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model?.Courses);
        Assert.IsTrue(model.Courses.Any());
        Assert.AreEqual(instructorId, (int)controller.ViewBag.InstructorID);
    }

    // ===================== Details Tests =====================

    [TestMethod]
    public void Details_ValidId_ReturnsInstructor()
    {
        // Arrange
        var instructorId = SeedInstructor();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Details(instructorId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.AreEqual("Doe", model!.LastName);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Details(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_NonExistentId_ReturnsNotFound()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Details(999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    // ===================== Create Tests =====================

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
    }

    [TestMethod]
    public void Create_Post_ValidModel_SavesAndRedirects()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            LastName = "NewProf",
            FirstMidName = "First",
            HireDate = new DateTime(2024, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = controller.Create(instructor, null!);

        // Assert
        Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        Assert.AreEqual(1, context.Instructors.Count());
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_SavesInstructorWithCourses()
    {
        // Arrange
        SeedCourses();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            LastName = "CourseProf",
            FirstMidName = "Test",
            HireDate = DateTime.Today
        };

        // Act
        var result = controller.Create(instructor, new[] { "2001", "2002" });

        // Assert
        Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        var saved = context.Instructors
            .Include(i => i.CourseAssignments)
            .First(i => i.LastName == "CourseProf");
        Assert.AreEqual(2, saved.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = controller.Create(instructor, null!);

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    // ===================== Edit Tests =====================

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsInstructorWithCourses()
    {
        // Arrange
        var (instructorId, _, _) = SeedInstructorWithCourseAndDepartment();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Edit(instructorId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.AreEqual("Smith", model!.LastName);
        Assert.IsNotNull(controller.ViewBag.Courses);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Edit((int?)null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    // ===================== Delete Tests =====================

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsInstructor()
    {
        // Arrange
        var instructorId = SeedInstructor();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Delete(instructorId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.AreEqual("Doe", model!.LastName);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Delete(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NonExistentId_ReturnsNotFound()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Arrange
        var (instructorId, _, _) = SeedInstructorWithCourseAndDepartment();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.DeleteConfirmed(instructorId);

        // Assert
        Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        Assert.IsNull(context.Instructors.Find(instructorId));
    }

    [TestMethod]
    public void DeleteConfirmed_NullsDepartmentReference()
    {
        // Arrange - create instructor who is also a department administrator
        int instructorId;
        int deptId;
        using (var seedContext = CreateContext())
        {
            var instructor = new Instructor
            {
                LastName = "Admin",
                FirstMidName = "Dept",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Office" }
            };
            seedContext.Instructors.Add(instructor);
            seedContext.SaveChanges();
            instructorId = instructor.ID;

            var dept = new Department
            {
                Name = "Administered Dept",
                Budget = 100000,
                StartDate = DateTime.Today,
                InstructorID = instructorId
            };
            seedContext.Departments.Add(dept);
            seedContext.SaveChanges();
            deptId = dept.DepartmentID;
        }
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        controller.DeleteConfirmed(instructorId);

        // Assert - department's InstructorID should be null
        var department = context.Departments.Find(deptId);
        Assert.IsNotNull(department);
        Assert.IsNull(department.InstructorID);
    }

    [TestMethod]
    public void DeleteConfirmed_SendsNotification()
    {
        // Arrange
        var (instructorId, _, _) = SeedInstructorWithCourseAndDepartment();
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        // Act
        controller.DeleteConfirmed(instructorId);

        // Assert
        using var svc = new ContosoUniversity.Services.NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.AreEqual("DELETE", notification.Operation);
    }
}

