using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class HomeControllerTests
{
    private string _dbName = null!;

    [TestInitialize]
    public void Setup()
    {
        _dbName = Guid.NewGuid().ToString();
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    private SchoolContext CreateContext() => TestHelpers.CreateContext(_dbName);

    // ===================== Index Tests =====================

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new HomeController(context);

        // Act
        var result = controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    // ===================== About Tests =====================

    [TestMethod]
    public void About_ReturnsEnrollmentDateGroups()
    {
        // Arrange
        using (var seedContext = CreateContext())
        {
            seedContext.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            seedContext.SaveChanges();
        }
        using var context = CreateContext();
        using var controller = new HomeController(context);

        // Act
        var result = controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // Two distinct enrollment dates
    }

    [TestMethod]
    public void About_GroupsStudentsByDate()
    {
        // Arrange
        using (var seedContext = CreateContext())
        {
            seedContext.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = new DateTime(2020, 9, 1) }
            );
            seedContext.SaveChanges();
        }
        using var context = CreateContext();
        using var controller = new HomeController(context);

        // Act
        var result = controller.About() as ViewResult;

        // Assert
        var model = result!.Model as List<EnrollmentDateGroup>;
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual(3, model[0].StudentCount);
        Assert.AreEqual(new DateTime(2020, 9, 1), model[0].EnrollmentDate);
    }

