using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private string _dbName = null!;

    [TestInitialize]
    public void Setup()
    {
        _dbName = Guid.NewGuid().ToString();
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    private SchoolContext CreateContext() => TestHelpers.CreateContext(_dbName);

    // ===================== GetNotifications Tests =====================

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - pre-populate the static queue
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "admin");
        svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "admin");

        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var jsonValue = result.Value;
        Assert.IsNotNull(jsonValue);

        // Verify the dynamic JSON object has expected properties
        var successProp = jsonValue.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(jsonValue));

        var countProp = jsonValue.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        var count = (int)countProp.GetValue(jsonValue)!;
        Assert.IsTrue(count >= 1, $"Expected at least 1 notification, got {count}");
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsEmptyNotifications()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var jsonValue = result.Value;
        Assert.IsNotNull(jsonValue);

        var successProp = jsonValue.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp!.GetValue(jsonValue));

        var countProp = jsonValue.GetType().GetProperty("count");
        Assert.AreEqual(0, countProp!.GetValue(jsonValue));
    }

    [TestMethod]
    public void GetNotifications_LimitsToTenNotifications()
    {
        // Arrange - add more than 10 notifications
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        var jsonValue = result.Value;
        Assert.IsNotNull(jsonValue);

        var countProp = jsonValue.GetType().GetProperty("count");
        var count = (int)countProp!.GetValue(jsonValue)!;
        Assert.IsTrue(count <= 10, $"Expected ≤10 notifications, got {count}");
    }

    [TestMethod]
    public void GetNotifications_ConsumesFromQueue()
    {
        // Arrange
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", EntityOperation.CREATE);

        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Act - first call should get the notification
        controller.GetNotifications();

        // Second call should get none (queue was consumed)
        var result2 = controller.GetNotifications();

        // Assert
        var jsonValue = result2.Value;
        var countProp = jsonValue!.GetType().GetProperty("count");
        Assert.AreEqual(0, countProp!.GetValue(jsonValue));
    }

    // ===================== MarkAsRead Tests =====================

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var jsonValue = result.Value;
        Assert.IsNotNull(jsonValue);

        var successProp = jsonValue.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp!.GetValue(jsonValue));
    }

    [TestMethod]
    public void MarkAsRead_NonExistentId_StillReturnsSuccess()
    {
        // Arrange - MarkAsRead is a no-op in the in-memory implementation
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.MarkAsRead(99999);

        // Assert
        var jsonValue = result.Value;
        var successProp = jsonValue!.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp!.GetValue(jsonValue));
    }

    // ===================== Index Tests =====================

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Arrange
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }
}

